     1â†’<!DOCTYPE html>
     2â†’<html lang="en">
     3â†’<head>
     4â†’  <meta charset="UTF-8">
     5â†’  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6â†’  <meta name="theme-color" content="#0a0a0f">
     7â†’
     8â†’  <!-- Open Graph / Social -->
     9â†’  <meta property="og:type" content="website">
    10â†’  <meta property="og:title" content="{{portfolioTitle}}">
    11â†’  <meta property="og:description" content="A portfolio of AI prompts and responses">
    12â†’  <meta property="og:image" content="{{ogImageUrl}}">
    13â†’  <meta property="og:url" content="{{portfolioUrl}}">
    14â†’  <meta name="twitter:card" content="summary_large_image">
    15â†’
    16â†’  <title>{{portfolioTitle}} â€” Promptfolio</title>
    17â†’  <link rel="stylesheet" href="assets/styles.css">
    18â†’</head>
    19â†’<body>
    20â†’  <header class="header">
    21â†’    <div class="container">
    22â†’      <h1 class="header-title">{{portfolioTitle}}</h1>
    23â†’      <p class="header-meta">Created {{createdAt}}</p>
    24â†’    </div>
    25â†’  </header>
    26â†’
    27â†’  <main class="container">
    28â†’    <div class="prompts-grid">
    29â†’      {{promptCards}}
    30â†’    </div>
    31â†’
    32â†’    <section class="share-section">
    33â†’      <p>Share this portfolio</p>
    34â†’      <div class="share-buttons">
    35â†’        <button class="btn btn-share" onclick="sharePortfolio()">Share</button>
    36â†’        <button class="btn btn-copy" onclick="copyLink()">Copy Link</button>
    37â†’      </div>
    38â†’    </section>
    39â†’  </main>
    40â†’
    41â†’  <footer class="footer">
    42â†’    <div class="container">
    43â†’      <p>Built with Promptfolio</p>
    44â†’    </div>
    45â†’  </footer>
    46â†’
    47â†’  <script>
    48â†’    async function sharePortfolio() {
    49â†’      if (navigator.share) {
    50â†’        try {
    51â†’          await navigator.share({
    52â†’            title: '{{portfolioTitle}}',
    53â†’            text: 'Check out this portfolio of AI prompts',
    54â†’            url: window.location.href
    55â†’          });
    56â†’        } catch (err) {
    57â†’          if (err.name !== 'AbortError') {
    58â†’            copyLink();
    59â†’          }
    60â†’        }
    61â†’      } else {
    62â†’        copyLink();
    63â†’      }
    64â†’    }
    65â†’
    66â†’    async function copyLink() {
    67â†’      try {
    68â†’        await navigator.clipboard.writeText(window.location.href);
    69â†’        const btn = document.querySelector('.btn-copy');
    70â†’        const originalText = btn.textContent;
    71â†’        btn.textContent = 'Copied!';
    72â†’        btn.classList.add('copy-success');
    73â†’        setTimeout(() => {
    74â†’          btn.textContent = originalText;
    75â†’          btn.classList.remove('copy-success');
    76â†’        }, 2000);
    77â†’      } catch (err) {
    78â†’        console.error('Failed to copy:', err);
    79â†’      }
    80â†’    }
    81â†’
    82â†’    async function copyPrompt(promptId) {
    83â†’      const card = document.getElementById(promptId);
    84â†’      const body = card.querySelector('.prompt-body').textContent;
    85â†’      try {
    86â†’        await navigator.clipboard.writeText(body);
    87â†’        const btn = card.querySelector('.btn-copy');
    88â†’        const originalText = btn.textContent;
    89â†’        btn.textContent = 'Copied!';
    90â†’        btn.classList.add('copy-success');
    91â†’        setTimeout(() => {
    92â†’          btn.textContent = originalText;
    93â†’          btn.classList.remove('copy-success');
    94â†’        }, 2000);
    95â†’      } catch (err) {
    96â†’        console.error('Failed to copy:', err);
    97â†’      }
    98â†’    }
    99â†’  </script>
   100â†’</body>
