     1â†’/**
     2â†’ * Claude Export JSON Parser
     3â†’ *
     4â†’ * Transforms Claude conversation export JSON files into structured Portfolio objects.
     5â†’ * Handles defensive parsing with multiple fallback strategies for schema drift.
     6â†’ */
     7â†’
     8â†’import { validateClaudeExport } from './schema.js';
     9â†’
    10â†’const FILE_SIZE_LIMIT = 5 * 1024 * 1024; // 5 MB
    11â†’
    12â†’/**
    13â†’ * Parses a Claude conversation export file
    14â†’ * @param {string} content - Raw file content
    15â†’ * @param {number} fileSize - Size of the file in bytes
    16â†’ * @returns {Portfolio} Parsed portfolio object
    17â†’ * @throws {Error} On parse failure
    18â†’ */
    19â†’export function parseClaudeExport(content, fileSize = 0) {
    20â†’  // Enforce size cap
    21â†’  if (fileSize > FILE_SIZE_LIMIT) {
    22â†’    throw new Error('File exceeds 5 MB limit. Please export a smaller conversation.');
    23â†’  }
    24â†’
    25â†’  if (!content || content.trim() === '') {
    26â†’    throw new Error('Empty file. Please upload a valid Claude export.');
    27â†’  }
    28â†’
    29â†’  // Try direct JSON parse first
    30â†’  let data;
    31â†’  try {
    32â†’    data = JSON.parse(content);
    33â†’  } catch (e) {
    34â†’    // Try stripping markdown fences
    35â†’    const stripped = stripMarkdownFences(content);
    36â†’    try {
    37â†’      data = JSON.parse(stripped);
    38â†’    } catch (e2) {
    39â†’      // Try recursive brace extraction
    40â†’      const extracted = extractJsonBlock(content);
    41â†’      if (extracted) {
    42â†’        try {
    43â†’          data = JSON.parse(extracted);
    44â†’        } catch (e3) {
    45â†’          // Fall through to raw text fallback
    46â†’          data = null;
    47â†’        }
    48â†’      }
    49â†’    }
    50â†’  }
    51â†’
    52â†’  // If we have data, validate and parse
    53â†’  if (data) {
    54â†’    const validation = validateClaudeExport(data);
    55â†’    if (validation.valid) {
    56â†’      return extractPortfolio(data);
    57â†’    }
    58â†’    // Schema validation failed but we have JSON - try to extract what we can
    59â†’    const partialExtract = extractPartialPortfolio(data);
    60â†’    if (partialExtract.prompts.length > 0) {
    61â†’      return partialExtract;
    62â†’    }
    63â†’  }
    64â†’
    65â†’  // Raw text fallback - render as plain text blocks
    66â†’  return createRawTextPortfolio(content);
    67â†’}
    68â†’
    69â†’/**
    70â†’ * Strips markdown code fences from content
    71â†’ * @param {string} content
    72â†’ * @returns {string}
    73â†’ */
    74â†’function stripMarkdownFences(content) {
    75â†’  // Match ```json ... ``` or ``` ... ```
    76â†’  const fenceRegex = /^```(?:json)?\s*([\s\S]*?)```$/m;
    77â†’  const match = content.match(fenceRegex);
    78â†’  if (match && match[1]) {
    79â†’    return match[1].trim();
    80â†’  }
    81â†’  return content;
    82â†’}
    83â†’
    84â†’/**
    85â†’ * Extracts the first JSON-like block using brace matching
    86â†’ * @param {string} content
    87â†’ * @returns {string|null}
    88â†’ */
    89â†’function extractJsonBlock(content) {
    90â†’  const startIdx = content.indexOf('{');
    91â†’  if (startIdx === -1) return null;
    92â†’
    93â†’  let braceCount = 0;
    94â†’  let inString = false;
    95â†’  let escape = false;
    96â†’
    97â†’  for (let i = startIdx; i < content.length; i++) {
    98â†’    const char = content[i];
    99â†’
   100â†’    if (escape) {
   101â†’      escape = false;
   102â†’      continue;
   103â†’    }
   104â†’
   105â†’    if (char === '\\') {
   106â†’      escape = true;
   107â†’      continue;
   108â†’    }
   109â†’
   110â†’    if (char === '"' && !escape) {
   111â†’      inString = !inString;
   112â†’      continue;
   113â†’    }
   114â†’
   115â†’    if (!inString) {
   116â†’      if (char === '{') braceCount++;
   117â†’      if (char === '}') {
   118â†’        braceCount--;
   119â†’        if (braceCount === 0) {
   120â†’          return content.substring(startIdx, i + 1);
   121â†’        }
   122â†’      }
   123â†’    }
   124â†’  }
   125â†’
   126â†’  return null;
   127â†’}
   128â†’
   129â†’/**
   130â†’ * Extracts a structured Portfolio from validated Claude export data
   131â†’ * @param {object} data - Validated Claude export
   132â†’ * @returns {Portfolio}
   133â†’ */
   134â†’function extractPortfolio(data) {
   135â†’  const conversation = data.conversation;
   136â†’  const messages = conversation.messages || [];
   137â†’
   138â†’  const prompts = [];
   139â†’  const images = [];
   140â†’
   141â†’  for (let i = 0; i < messages.length; i++) {
   142â†’    const msg = messages[i];
   143â†’    const content = normalizeContent(msg.content);
   144â†’
   145â†’    // Extract images from content
   146â†’    const extractedImages = extractImagesFromContent(msg.content, msg.role, i);
   147â†’    images.push(...extractedImages);
